// === Score: Quick Wins ===
// Site-wide quick-win finder. Pure deterministic scoring on GSC per-page data.
// No fetch, no LLM. Each page is scored on two signals that are fixable fast:
//   1. Striking distance — ranking 5–15, close to page one
//   2. High impressions, low CTR — shown a lot, barely clicked (weak title/meta)
// Output is a ranked queue; each row links into the page optimizer.

const inp = $input.first().json;
const rows = Array.isArray(inp.rows) ? inp.rows : [];

// --- no data yet (new property / weekend): return a valid empty result ---
if (rows.length === 0) {
  return [{ json: {
    summary: { hasData: false, totalPages: 0, quickWins: 0, generatedAt: new Date().toISOString() },
    quickWins: []
  }}];
}

// --- normalise GSC rows (keys[0] is the page URL when dimension = page) ---
const pages = rows.map(r => ({
  url: Array.isArray(r.keys) ? r.keys[0] : String(r.keys || ''),
  clicks: r.clicks || 0,
  impressions: r.impressions || 0,
  ctr: r.ctr || 0,
  position: r.position || 0
}));

const wins = [];

for (const p of pages) {
  // --- Signal 1: striking distance (position 5–15, real impressions) ---
  if (p.position >= 5 && p.position <= 15 && p.impressions >= 20) {
    // closer to page one + more impressions = higher value
    const score = (16 - p.position) * 10 + Math.min(p.impressions / 10, 100);
    wins.push({
      url: p.url,
      type: 'Striking distance',
      severity: p.position <= 10 ? 'high' : 'medium',
      score: Math.round(score),
      position: Math.round(p.position * 10) / 10,
      impressions: p.impressions,
      clicks: p.clicks,
      ctr: Math.round(p.ctr * 1000) / 10, // percent, 1 decimal
      why: `Ranking ${p.position.toFixed(1)} with ${p.impressions} impressions. A focused title, meta and content pass can push this onto page one.`
    });
  }

  // --- Signal 2: high impressions, low CTR (weak title/meta) ---
  // only flag if NOT already a striking-distance win, to avoid double-listing
  else if (p.impressions >= 100 && p.ctr < 0.02) {
    const score = Math.min(p.impressions / 5, 200) + (0.02 - p.ctr) * 1000;
    wins.push({
      url: p.url,
      type: 'Low CTR',
      severity: p.impressions >= 500 ? 'high' : 'medium',
      score: Math.round(score),
      position: Math.round(p.position * 10) / 10,
      impressions: p.impressions,
      clicks: p.clicks,
      ctr: Math.round(p.ctr * 1000) / 10,
      why: `${p.impressions} impressions but only ${(p.ctr * 100).toFixed(1)}% CTR. The page shows up — a stronger title and meta would win more of those clicks.`
    });
  }
}

// --- rank by score, highest value first ---
wins.sort((a, b) => b.score - a.score);

const summary = {
  hasData: true,
  totalPages: pages.length,
  quickWins: wins.length,
  strikingDistance: wins.filter(w => w.type === 'Striking distance').length,
  lowCtr: wins.filter(w => w.type === 'Low CTR').length,
  generatedAt: new Date().toISOString()
};

return [{ json: { summary, quickWins: wins } }];
